30	export const setRedirectStorage = () => {
31	  const urlInfo = new URL(window.location.href)
32	  const url = urlInfo.origin + '/emergency-response'
33	  const value = encodeURIComponent(url)
34	  window.sessionStorage.setItem(redirectStorageKey, value)
35	  return value
36	}
