1	import { useEffect } from 'react'
2	import { Navigate, Outlet, useLocation, useNavigate } from 'react-router-dom'
3	import { getToken } from '@common/utils/localStorage'
4	
5	const ContractorGuard = () => {
6	  const { pathname } = useLocation()
7	  const navigate = useNavigate()
8	
9	  useEffect(() => {
10	    if (pathname === '/contractor') {
11	      navigate('/contractor/list', { replace: true })
12	    }
13	  }, [pathname, navigate])
14	
15	  if (!getToken()) {
16	    return <Navigate to='/contractor-login' replace />
17	  }
18	
19	  return <Outlet />
20	}
21	
22	export default ContractorGuard
