1	import { useCallback } from 'react'
2	import { logoutRedirectURL } from '@common/constants/env'
3	import { contractorLogout } from '@/service/apis/contractorPortal'
4	import { getToken, removeToken } from '@common/utils/localStorage'
5	
6	const useContractorLogout = () => {
7	  return useCallback(() => {
8	    if (logoutRedirectURL) {
9	      const token = getToken() ?? ''
10	      removeToken()
11	      window.location.href = `${logoutRedirectURL}?jToken=${token}`
12	    } else {
13	      contractorLogout({}).finally(() => {
14	        removeToken()
15	        window.location.replace('/contractor-login')
16	      })
17	    }
18	  }, [])
19	}
20	
21	export default useContractorLogout
